def classify_triangle_ok_6(a, b, c):
    a, b, c = sorted([a, b, c])
    if a <= 0 or a + b <= c:
        return "invalid"
    if a == b == c:
        return "equilateral"
    if a * a + b * b == c * c:
        return "right-angled"
    if a == b or b == c:
        return "isosceles"
    return "scalene"

assert classify_triangle_ok_6(3, 4, 5) == "right-angled"
assert classify_triangle_ok_6(2, 2, 3) == "isosceles"
assert classify_triangle_ok_6(5, 5, 11) == "invalid"

