def classify_triangle_ok_96(a, b, c):
    a, b, c = sorted([a, b, c])
    if a <= 0 or a + b <= c:
        return "invalid"
    if a == b == c:
        return "equilateral"
    if a * a + b * b == c * c:
        return "right-angled"
    if a == b or b == c:
        return "isosceles"
    return "scalene"

